VALUES
  ('promotion-d592fc58-moex-00108', 'promotion-d592fc58', 'promotion-d592fc58-moex-112-9b7ab1bb', 'sub-promotion-d592fc58-02', NULL, 'single_choice', '下列關於動產善意取得之敘述，何者錯誤？', '["受讓人若係明知或因重大過失而不知讓與人無讓與之權利者，不得主張動產所有權之善意取得", "動產占有之受讓，若係依占有改定方式為之者，須受讓人受現實交付且交付時善意為限，始受 占有法律規定之保護", "占有物如係盜贓，原占有人自喪失占有之時起二年內，得向善意受讓之現占有人請求回復其物， 並自請求時起，回復其原來之權利", "占有之盜贓、遺失物如係金錢或未記載權利人之有價證券，原占有人即不得向其善意受讓之現 占有人請求回復"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:28:37+00:00", "source_pdf_sha1": "0635b758199f", "answer_pdf_sha1": "cdba98d79113", "source_family": "moex-gov-tw", "moex": {"exam_code": "112170", "c": "135", "s": "0501", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法", "year": "112", "exam_name": "112年公務人員升官等考試、112年關務人員升官等考試、112年交通事業鐵路人員升資考試、112年交通事業港務人員升資考試", "original_question_number": 16, "answer_corrected": false, "flags": [], "civil_slug": "promotion", "civil_category": "商業行政"}'::jsonb, NULL),
  ('promotion-d592fc58-moex-00109', 'promotion-d592fc58', 'promotion-d592fc58-moex-112-9b7ab1bb', 'sub-promotion-d592fc58-02', NULL, 'single_choice', '下列何者因有違物權法定主義之規定，而不得辦理登記？', '["以共有之土地為共有人中之一人所設定之普通地上權", "以典權為標的物所設定之不動產質權", "以農育權為標的物所設定之權利抵押權", "以自己之不動產所設定之不動產役權"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:28:37+00:00", "source_pdf_sha1": "0635b758199f", "answer_pdf_sha1": "cdba98d79113", "source_family": "moex-gov-tw", "moex": {"exam_code": "112170", "c": "135", "s": "0501", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法", "year": "112", "exam_name": "112年公務人員升官等考試、112年關務人員升官等考試、112年交通事業鐵路人員升資考試、112年交通事業港務人員升資考試", "original_question_number": 17, "answer_corrected": false, "flags": [], "civil_slug": "promotion", "civil_category": "商業行政"}'::jsonb, NULL),
  ('promotion-d592fc58-moex-00110', 'promotion-d592fc58', 'promotion-d592fc58-moex-112-9b7ab1bb', 'sub-promotion-d592fc58-02', NULL, 'single_choice', '下列何者非屬所有權取得時效之中斷事由？', '["占有人變為他主占有之意思占有", "占有人變為非和平或非公然占有", "占有人變為惡意或有過失占有", "所有權人依民法第767條規定訴請返還占有物"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:28:37+00:00", "source_pdf_sha1": "0635b758199f", "answer_pdf_sha1": "cdba98d79113", "source_family": "moex-gov-tw", "moex": {"exam_code": "112170", "c": "135", "s": "0501", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法", "year": "112", "exam_name": "112年公務人員升官等考試、112年關務人員升官等考試、112年交通事業鐵路人員升資考試、112年交通事業港務人員升資考試", "original_question_number": 18, "answer_corrected": false, "flags": [], "civil_slug": "promotion", "civil_category": "商業行政"}'::jsonb, NULL),
  ('promotion-d592fc58-moex-00111', 'promotion-d592fc58', 'promotion-d592fc58-moex-112-9b7ab1bb', 'sub-promotion-d592fc58-02', NULL, 'single_choice', '依民法第962條規定，占有被侵奪者，占有人得請求返還其占有物。下列何者非該條所定之主體？', '["無權占有人", "間接占有人", "直接占有人", "占有輔助人 13540 13740"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:28:37+00:00", "source_pdf_sha1": "0635b758199f", "answer_pdf_sha1": "cdba98d79113", "source_family": "moex-gov-tw", "moex": {"exam_code": "112170", "c": "135", "s": "0501", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法", "year": "112", "exam_name": "112年公務人員升官等考試、112年關務人員升官等考試、112年交通事業鐵路人員升資考試、112年交通事業港務人員升資考試", "original_question_number": 19, "answer_corrected": false, "flags": [], "civil_slug": "promotion", "civil_category": "商業行政"}'::jsonb, NULL),
  ('promotion-d592fc58-moex-00112', 'promotion-d592fc58', 'promotion-d592fc58-moex-112-9b7ab1bb', 'sub-promotion-d592fc58-02', NULL, 'single_choice', '關於親屬之種類與親等之計算，下列敘述何者正確？', '["稱直系血親者，僅係指與己身出於同源之法定血親", "稱姻親者，謂血親之配偶、配偶之血親及配偶之血親之配偶", "血親之配偶，其親系與親等之計算，皆從其與旁系血親之配偶之親系與親等", "姻親關係，因具法定分居事由而消滅"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:28:37+00:00", "source_pdf_sha1": "0635b758199f", "answer_pdf_sha1": "cdba98d79113", "source_family": "moex-gov-tw", "moex": {"exam_code": "112170", "c": "135", "s": "0501", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法", "year": "112", "exam_name": "112年公務人員升官等考試、112年關務人員升官等考試、112年交通事業鐵路人員升資考試、112年交通事業港務人員升資考試", "original_question_number": 20, "answer_corrected": false, "flags": [], "civil_slug": "promotion", "civil_category": "商業行政"}'::jsonb, NULL),
  ('promotion-d592fc58-moex-00113', 'promotion-d592fc58', 'promotion-d592fc58-moex-112-9b7ab1bb', 'sub-promotion-d592fc58-02', NULL, 'single_choice', '甲乙結婚後，乙與丙合意性交，甲發現後持刀殺丙未遂。甲因而被判處有期徒刑三年確定。下列 敘述何者錯誤？', '["甲乙如經協議離婚，甲並無贍養費請求權", "甲服刑期滿後，再以乙與丙合意性交訴請離婚，已逾除斥期間", "甲乙就難以維持婚姻均應負責，故雙方均不得請求離婚", "乙知悉甲被判刑確定後已逾一年者，不得請求離婚"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:28:37+00:00", "source_pdf_sha1": "0635b758199f", "answer_pdf_sha1": "cdba98d79113", "source_family": "moex-gov-tw", "moex": {"exam_code": "112170", "c": "135", "s": "0501", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法", "year": "112", "exam_name": "112年公務人員升官等考試、112年關務人員升官等考試、112年交通事業鐵路人員升資考試、112年交通事業港務人員升資考試", "original_question_number": 21, "answer_corrected": false, "flags": [], "civil_slug": "promotion", "civil_category": "商業行政"}'::jsonb, NULL),
  ('promotion-d592fc58-moex-00114', 'promotion-d592fc58', 'promotion-d592fc58-moex-112-9b7ab1bb', 'sub-promotion-d592fc58-02', NULL, 'single_choice', '未婚之乙女與已婚之甲男發生性行為，致生一子丁。甲男為維持婚姻，逃避之。甲在乙女之兄長 丙持刀脅迫下認領丁。關於甲之認領，下列敘述何者正確？', '["認領有效且不得撤銷", "認領無效", "認領得撤銷", "須得甲男之妻承認，始生效力"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:28:37+00:00", "source_pdf_sha1": "0635b758199f", "answer_pdf_sha1": "cdba98d79113", "source_family": "moex-gov-tw", "moex": {"exam_code": "112170", "c": "135", "s": "0501", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法", "year": "112", "exam_name": "112年公務人員升官等考試、112年關務人員升官等考試、112年交通事業鐵路人員升資考試、112年交通事業港務人員升資考試", "original_question_number": 22, "answer_corrected": false, "flags": [], "civil_slug": "promotion", "civil_category": "商業行政"}'::jsonb, NULL),
  ('promotion-d592fc58-moex-00115', 'promotion-d592fc58', 'promotion-d592fc58-moex-112-9b7ab1bb', 'sub-promotion-d592fc58-02', NULL, 'single_choice', '下列關於遺囑撤回之敘述，何者正確？', '["遺囑人得隨時以自書或錄影錄音之遺囑方式，撤回遺囑之全部或一部，經全體遺囑受益人同意 後，其撤回始生效力", "以自書方式立遺囑者，其發現前後遺囑有相牴觸之情狀，立遺囑人之配偶或直系血親卑親屬應 共同聲請刑事鑑定機關進行確認", "遺囑人於為遺囑後所為之行為與遺囑有相牴觸者，其牴觸部分，遺囑視為撤回", "遺囑人故意塗銷遺囑之特定部分，或在遺囑上記明特定部分廢棄者，該部分之遺囑視為撤回， 並應經全體遺囑受益人見證且簽名之"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:28:37+00:00", "source_pdf_sha1": "0635b758199f", "answer_pdf_sha1": "cdba98d79113", "source_family": "moex-gov-tw", "moex": {"exam_code": "112170", "c": "135", "s": "0501", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法", "year": "112", "exam_name": "112年公務人員升官等考試、112年關務人員升官等考試、112年交通事業鐵路人員升資考試、112年交通事業港務人員升資考試", "original_question_number": 23, "answer_corrected": false, "flags": [], "civil_slug": "promotion", "civil_category": "商業行政"}'::jsonb, NULL),
  ('promotion-d592fc58-moex-00116', 'promotion-d592fc58', 'promotion-d592fc58-moex-112-9b7ab1bb', 'sub-promotion-d592fc58-02', NULL, 'single_choice', '下列關於繼承回復請求權之敘述，何者正確？', '["繼承回復請求權與個別物上請求權係屬真正繼承人分別獨立而併存之權利", "繼承回復請求權於時效完成後，真正繼承人喪失其合法取得之繼承權", "繼承權被侵害者，自命繼承人之被告或其法定代理人得請求回復之", "繼承回復請求權，自知悉被侵害之時起，十年間不行使而消滅"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:28:37+00:00", "source_pdf_sha1": "0635b758199f", "answer_pdf_sha1": "cdba98d79113", "source_family": "moex-gov-tw", "moex": {"exam_code": "112170", "c": "135", "s": "0501", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法", "year": "112", "exam_name": "112年公務人員升官等考試、112年關務人員升官等考試、112年交通事業鐵路人員升資考試、112年交通事業港務人員升資考試", "original_question_number": 24, "answer_corrected": false, "flags": [], "civil_slug": "promotion", "civil_category": "商業行政"}'::jsonb, NULL),
  ('promotion-d592fc58-moex-00117', 'promotion-d592fc58', 'promotion-d592fc58-moex-112-9b7ab1bb', 'sub-promotion-d592fc58-02', NULL, 'single_choice', '甲男乙女為夫妻，依法約定採夫妻分別財產制。甲乙生有一女丙。甲乙於民國（下同）105 年間 依法收養已婚之丁為養子時，丁與其妻A生有一子B，B年5歲。於108年間，丁與A再生一女', '["", "", "丁於110年1月10日，與甲、乙共同出遊，遭意外，丁當日死亡，甲於意外後3日死亡，乙 重傷。甲之好友為庚，丁之好友為辛，甲與丁生前均立遺囑，分別對庚及辛為遺贈。下列敘述何 者正確？", ""]'::jsonb, 2, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:28:37+00:00", "source_pdf_sha1": "0635b758199f", "answer_pdf_sha1": "cdba98d79113", "source_family": "moex-gov-tw", "moex": {"exam_code": "112170", "c": "135", "s": "0501", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法", "year": "112", "exam_name": "112年公務人員升官等考試、112年關務人員升官等考試、112年交通事業鐵路人員升資考試、112年交通事業港務人員升資考試", "original_question_number": 25, "answer_corrected": false, "flags": ["incomplete_options"], "civil_slug": "promotion", "civil_category": "商業行政"}'::jsonb, NULL)
